class Solution:
    def canBeEqual(self, s1: str, s2: str) -> bool:
        # Check if characters at positions 0 and 2 can be swapped to match s2
        # Check if characters at positions 1 and 3 can be swapped to match s2
        return sorted(s1[::2]) == sorted(s2[::2]) and sorted(s1[1::2]) == sorted(s2[1::2])
